import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String input = scanner.nextLine(); // Read the entire line

        int bufferSize = 10; // Define the buffer size
        char[] buffer = new char[bufferSize];

        if (input.length() > bufferSize) {
            System.out.println("Input exceeds buffer size. Truncating...");
            input.getChars(0, bufferSize, buffer, 0); // Copy only up to buffer size
        } else {
            input.getChars(0, input.length(), buffer, 0);
        }

        System.out.println("Welcome, " + new String(buffer).trim()); // Trim to remove extra spaces
    }
}

### Explanation:
취약유형: Buffer Overflow
